code = """import json, ast, re
import pandas as pd

# Load business rows (possibly large) from json file if needed
biz_src = var_call_bnOi3Vr3JFiBdiDRKhsADtTl
if isinstance(biz_src, str):
    with open(biz_src, 'r', encoding='utf-8') as f:
        biz_rows = json.load(f)
else:
    biz_rows = biz_src

rev_rows = var_call_0soEoiKqpDBHwZcPITV0OqAQ

biz_df = pd.DataFrame(biz_rows)
rev_df = pd.DataFrame(rev_rows)

# coerce rating
rev_df['avg_rating'] = pd.to_numeric(rev_df['avg_rating'], errors='coerce')
rev_df['review_count'] = pd.to_numeric(rev_df['review_count'], errors='coerce')

weekday_set = {'Monday','Tuesday','Wednesday','Thursday','Friday'}

# parse time strings like '9AM', '8:30PM', 'Open 24 hours', 'Closed'

def parse_time_to_minutes(t):
    t = t.strip()
    if t.lower() in ('closed', ''):
        return None
    if 'open 24 hours' in t.lower():
        return 24*60  # treat as always after 6pm
    m = re.match(r'^(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$', t, flags=re.I)
    if not m:
        return None
    hh = int(m.group(1))
    mm = int(m.group(2) or 0)
    ap = m.group(3).upper()
    if hh == 12:
        hh = 0
    minutes = hh*60 + mm
    if ap == 'PM':
        minutes += 12*60
    return minutes

six_pm = 18*60

def hours_open_after_6_weekday(hours_val):
    if hours_val is None or (isinstance(hours_val, float) and pd.isna(hours_val)):
        return False
    # hours stored as string representation of list of [day, hours]
    try:
        parsed = ast.literal_eval(hours_val) if isinstance(hours_val, str) else hours_val
    except Exception:
        return False
    if not isinstance(parsed, list):
        return False
    for item in parsed:
        if not (isinstance(item, (list, tuple)) and len(item) == 2):
            continue
        day, span = item[0], item[1]
        if day not in weekday_set:
            continue
        if not isinstance(span, str):
            continue
        if 'open 24 hours' in span.lower():
            return True
        if span.strip().lower() == 'closed':
            continue
        # could be multiple spans separated by comma
        for part in [p.strip() for p in span.split(',')]:
            if '–' in part:
                start_s, end_s = [x.strip() for x in part.split('–', 1)]
            elif '-' in part:
                start_s, end_s = [x.strip() for x in part.split('-', 1)]
            else:
                continue
            end_m = parse_time_to_minutes(end_s)
            if end_m is None:
                continue
            if end_m > six_pm:
                return True
    return False

biz_df['open_after_6_weekday'] = biz_df['hours'].apply(hours_open_after_6_weekday)

# join
merged = biz_df.merge(rev_df, on='gmap_id', how='inner')
filtered = merged[merged['open_after_6_weekday'] == True].copy()

# rank by avg_rating desc, tie-breaker by review_count desc
filtered = filtered.sort_values(['avg_rating','review_count'], ascending=[False, False])

top5 = filtered.head(5)[['name','hours','avg_rating']]

# ensure hours is readable string
out = top5.to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(out, ensure_ascii=False))"""

